sparql_templates.parameters:
PREFIX rdf:      <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:     <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd:      <http://www.w3.org/2001/XMLSchema#>
PREFIX biolink:  <https://w3id.org/biolink/vocab/>
PREFIX tkprop:   <https://takahuman.ai/kg/prop/>
PREFIX tktype:   <https://takahuman.ai/kg/type/>
PREFIX tknode:   <https://takahuman.ai/kg/node/>

SELECT ?subject ?subjectLabel ?param ?family ?parameter ?value ?unit ?quote ?sourceType ?tableId ?cellId ?analyteRole ?measuredAnalyte ?measuredAnalyteLabel ?normalizedSubjectId ?normalizedMeasuredAnalyte ?normalizedDiseaseId ?diseaseContext ?diseaseLabel
       (GROUP_CONCAT(DISTINCT ?drugContext; separator="|") AS ?drugContexts)
       (GROUP_CONCAT(DISTINCT ?targetContext; separator="|") AS ?targetContexts)
       (GROUP_CONCAT(DISTINCT ?mutationContext; separator="|") AS ?mutationContexts)
       (GROUP_CONCAT(DISTINCT ?cellLineContext; separator="|") AS ?cellLineContexts)
       (GROUP_CONCAT(DISTINCT ?assayContext; separator="|") AS ?assayContexts)
       (GROUP_CONCAT(DISTINCT ?matrixContext; separator="|") AS ?matrixContexts)
       (GROUP_CONCAT(DISTINCT ?speciesContext; separator="|") AS ?speciesContexts)
       (GROUP_CONCAT(DISTINCT ?pdContextQuality; separator="|") AS ?pdContextQualities)
WHERE {
  ?subject biolink:has_attribute ?param .
  ?subject rdfs:label ?subjectLabel .
  ?param a tktype:ParameterValue ;
         tkprop:parameter_class ?family ;
         tkprop:parameter_type ?parameter .
  OPTIONAL { ?param tkprop:value_num ?value . }
  OPTIONAL { ?param tkprop:unit ?unit . }
  OPTIONAL { ?param tkprop:analyte_role ?analyteRole . }
  OPTIONAL { ?param tkprop:measured_analyte ?measuredAnalyte . ?measuredAnalyte rdfs:label ?measuredAnalyteLabel . }
  OPTIONAL { ?param tkprop:normalized_subject_id ?normalizedSubjectId . }
  OPTIONAL { ?param tkprop:normalized_measured_analyte ?normalizedMeasuredAnalyte . }
  OPTIONAL { ?param tkprop:normalized_disease_id ?normalizedDiseaseId . }
  OPTIONAL { ?param tkprop:disease_context ?diseaseContext . ?diseaseContext rdfs:label ?diseaseLabel . }
  OPTIONAL { ?param tkprop:context_drug ?drugContext . }
  OPTIONAL { ?param tkprop:context_target ?targetContext . }
  OPTIONAL { ?param tkprop:context_mutation ?mutationContext . }
  OPTIONAL { ?param tkprop:context_cell_line ?cellLineContext . }
  OPTIONAL { ?param tkprop:context_assay ?assayContext . }
  OPTIONAL { ?param tkprop:context_matrix ?matrixContext . }
  OPTIONAL { ?param tkprop:context_species ?speciesContext . }
  OPTIONAL { ?param tkprop:context_pd_parameter_context_quality ?pdContextQuality . }
  OPTIONAL {
    ?param tkprop:has_evidence_anchor ?evidence .
    OPTIONAL { ?evidence tkprop:evidence_quote ?quote . }
    OPTIONAL { ?evidence tkprop:evidence_source_type ?sourceType . }
    OPTIONAL { ?evidence tkprop:evidence_table_id ?tableId . }
    OPTIONAL { ?evidence tkprop:cell_id ?cellId . }
  }
}
GROUP BY ?subject ?subjectLabel ?param ?family ?parameter ?value ?unit ?quote ?sourceType ?tableId ?cellId ?analyteRole ?measuredAnalyte ?measuredAnalyteLabel ?normalizedSubjectId ?normalizedMeasuredAnalyte ?normalizedDiseaseId ?diseaseContext ?diseaseLabel
LIMIT 100

